class Solution {
    public String greatestLetter(String s) {
        char[] chars = s.toLowerCase().toCharArray();
        Arrays.sort(chars);
        StringBuilder result = new StringBuilder();
        for (char c : chars) {
            if (Character.isUpperCase(c)) {
                result.append(c);
                break;
            }
        }
        return result.toString();
    }
}
